def _format_number(value):
    """
    Format a numeric result into a canonical string form.
    - Integers returned without decimal point.
    - Floats normalized, removing trailing zeros where appropriate.
    """
    # Normalize ints
    if isinstance(value, int):
        return str(value)

    # Normalize floats
    if isinstance(value, float):
        # Check for NaN or Infinity without importing math
        if value != value:
            raise ValueError("Result is NaN")
        if value == float("inf") or value == float("-inf"):
